1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
3	const CURSE_SURCHARGE_RATE = 0.5;
4	const COMPONENT_BASE_PRICE = 25;
5	const COMPONENT_BLOCK_SIZE = 3;
6	const COMPONENT_BLOCK_PRICE = 60;
7	
8	const BASE_PRICE_BY_ITEM_TYPE: Record<string, number> = {
9	  sword: 100,
10	  amulet: 60,
11	  staff: 80,
12	  potion: 40,
13	};
14	
15	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
16	
17	type Item = { type: string; cursed?: boolean };
18	type Customer = { yearsWithMHPCO: number };
19	
20	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
21	
22	const mainItemBasePrice = (item: Item): number =>
23	  BASE_PRICE_BY_ITEM_TYPE[item.type] ?? 0;
24	
25	const componentGroupBasePrice = (count: number): number =>
26	  count === COMPONENT_BLOCK_SIZE
27	    ? COMPONENT_BLOCK_PRICE
28	    : count * COMPONENT_BASE_PRICE;
29	
30	const groupComponentsByType = (items: Item[]): Map<string, number> => {
31	  const groups = new Map<string, number>();
32	  for (const item of items) {
33	    if (!isComponent(item)) continue;
34	    groups.set(item.type, (groups.get(item.type) ?? 0) + 1);
35	  }
36	  return groups;
37	};
38	
39	const basePremiumGroups = (items: Item[]): number[] => {
40	  const mainItemPremiums = items
41	    .filter((item) => !isComponent(item))
42	    .map(mainItemBasePrice);
43	  const componentGroupPremiums = [...groupComponentsByType(items).values()].map(
44	    componentGroupBasePrice,
45	  );
46	  return [...mainItemPremiums, ...componentGroupPremiums];
47	};
48	
49	const itemSurcharges = (items: Item[]): number => {
50	  let total = 0;
51	  for (const item of items) {
52	    const base = mainItemBasePrice(item);
53	    if (item.cursed) total += base * CURSE_SURCHARGE_RATE;
54	  }
55	  return total;
56	};
57	
58	export const quote = (_customer: Customer, items: Item[]): number => {
59	  const policyBasePremium = basePremiumGroups(items).reduce(
60	    (sum, premium) => sum + premium,
61	    0,
62	  );
63	  const firstInsuranceSurcharge =
64	    policyBasePremium * FIRST_INSURANCE_SURCHARGE_RATE;
65	  const surcharges = itemSurcharges(items);
66	  return Math.ceil(
67	    policyBasePremium + firstInsuranceSurcharge + surcharges + PROCESSING_FEE,
68	  );
69	};
70	
71	export const claim = (..._args: unknown[]): unknown => {
72	  return undefined;
73	};
